const msg = $input.first().json.body.message;
const call = msg.call ?? {};
const vars = call?.assistantOverrides?.variableValues ?? {};
const artifact = msg.artifact ?? {};

// SIP headers (case-insensitive)
const rawSip = call?.customer?.sipHeaders ?? call?.sipHeaders ?? {};
const sip = {};
for (const [k, v] of Object.entries(rawSip)) {
  if (typeof v === 'string') sip[k.toLowerCase()] = v;
}

const rawMessages = artifact.messages ?? [];
const transcriptMessages = rawMessages
  .filter(m => m.message && typeof m.message === 'string' && m.message.trim() !== '' && m.role !== 'system')
  .map(m => ({ role: m.role, text: m.message.trim() }));

const transcriptText = artifact.transcript
  ?? transcriptMessages.map(m => `${m.role}: ${m.text}`).join('\n');

// Vapi-End-of-Call-Report als Vorab-Hinweis an den Claude-Analyzer
const vapiEndReport = msg.analysis ?? msg.structuredData ?? null;

return [{
  json: {
    // Priorität: variableValues → SIP-Header; Server resolved zusätzlich per Phone oder Vapi-Call-ID
    sales_call_id: vars.sales_call_id ?? sip['x-sales-call-id'] ?? null,
    sales_lead_id: vars.sales_lead_id ?? sip['x-sales-lead-id'] ?? null,
    // Für Server-side-Resolution (siehe /api/sales/call-analyse)
    customer_phone: call?.customer?.number ?? null,
    vapi_call_id: call?.id ?? null,
    // Call-Meta
    started_at: msg.startedAt ?? null,
    ended_at: msg.endedAt ?? null,
    recording_url: artifact.recordingUrl ?? null,
    transcript_messages: transcriptMessages,
    transcript_text: transcriptText,
    end_reason: msg.endedReason ?? null,
    vapi_end_report: vapiEndReport
  }
}];
